// Validate incoming payload. FastAPI sends:
//   { action, orderId, orderRef, orderNumber, parentInvoiceId, amount, label }
const body = items[0].json.body || items[0].json;
const required = ['action', 'orderId', 'orderNumber', 'parentInvoiceId', 'amount'];
const missing = required.filter(k => body[k] === undefined || body[k] === null || body[k] === '');
if (missing.length) {
  throw new Error('Missing required fields: ' + missing.join(', '));
}
if (body.action !== 'credit_note' && body.action !== 'invoice') {
  throw new Error(`Unsupported action: ${body.action}. Use 'credit_note' or 'invoice'.`);
}
const amount = Number(body.amount);
if (!Number.isFinite(amount) || amount <= 0) {
  throw new Error('amount must be a positive number (we toggle direction via action type)');
}
return [{ json: {
  action: body.action,
  orderId: String(body.orderId),
  orderRef: body.orderRef || null,
  orderNumber: String(body.orderNumber),
  parentInvoiceId: String(body.parentInvoiceId),
  amount: Math.round(amount * 100) / 100,
  label: body.label || `eBay reconciliation - ${body.orderNumber}`,
}}];

// Combine validated input with the parent invoice to build the Dolibarr POST body.
const input = $('Validate input').first().json;
const parent = items[0].json;
if (!parent || !parent.socid) {
  throw new Error('Parent invoice ' + input.parentInvoiceId + ' has no socid; cannot create adjustment');
}
const nowUnix = Math.floor(Date.now() / 1000);
const payload = {
  socid: parent.socid,
  type: input.action === 'credit_note' ? 2 : 0,
  ref_client: input.orderNumber,
  date: nowUnix,
  note_private: `Auto-created via eBay reconciliation. eBay order: ${input.orderNumber}. Source invoice: ${parent.ref} (id ${parent.id}).`,
  lines: [{
    desc: input.label,
    qty: 1,
    subprice: input.amount,
    tva_tx: 0,
  }],
};
if (input.action === 'credit_note') {
  payload.fk_facture_source = input.parentInvoiceId;
}
return [{ json: { _input: input, _parent: { id: parent.id, ref: parent.ref, socid: parent.socid }, _payload: payload } }];

// Parse the create-document response: Dolibarr returns the new invoice id as
// either a bare integer or {error: ...}. Stash newDocId on the context for the
// rest of the chain.
const raw = items[0].json;
const input = $('Validate input').first().json;
const parent = $('Build Dolibarr payload').first().json._parent;

let newId = null;
if (typeof raw === 'number') newId = raw;
else if (typeof raw === 'string' && /^\d+$/.test(raw)) newId = Number(raw);
else if (raw && typeof raw === 'object' && raw.id) newId = raw.id;

if (!newId) {
  const msg = (raw && raw.error && (raw.error.message || raw.error['0'])) || JSON.stringify(raw).slice(0, 400);
  throw new Error('Create failed: ' + msg);
}

return [{ json: { _input: input, _parent: parent, newDocId: String(newId) } }];

// Validate response: full invoice object with assigned ref (e.g. IC2605-0521).
const raw = items[0].json;
const prior = $('Parse create response').first().json;
if (raw && raw.error) {
  throw new Error('Validate failed: ' + (raw.error.message || JSON.stringify(raw.error)));
}
const validatedRef = raw && raw.ref ? raw.ref : null;
const input = prior._input;
return [{ json: {
  ...prior,
  validatedRef,
  action: input.action,
}}];

// The discounts response is a list of objects. Find the entry whose
// fk_facture_source equals our newly-validated CN id; that's the rowid to apply.
const prior = $('Parse validate response').first().json;
const all = items.map(i => i.json);
const rowid = (() => {
  for (const x of all) {
    if (String(x.fk_facture_source) === String(prior.newDocId)) return String(x.rowid);
  }
  return null;
})();
if (!rowid) {
  const debug = all.slice(0, 3).map(x => `ref=${x.ref} src=${x.fk_facture_source} rowid=${x.rowid}`).join(' | ');
  throw new Error(`Could not find discount rowid for new CN (newDocId=${prior.newDocId}). Sample: ${debug}`);
}
return [{ json: { ...prior, discountRowid: rowid } }];

// Final shape. Accepts items from EITHER branch:
//   - credit_note path: came through 'POST usediscount on parent' (HTTP response)
//   - invoice path: came through 'IF credit_note?' false branch (carries the
//     parse-validate context as $json)
// In both cases the prior ctx is in $('Parse validate response').first().json.
const ctx = $('Parse validate response').first().json;
const input = $('Validate input').first().json;
const parent = ctx._parent;
const newId = ctx.newDocId;
const validatedRef = ctx.validatedRef;
const action = input.action;

let applied = false;
let appliedDiscountRowid = null;
let usedResult = null;
if (action === 'credit_note') {
  // For CN path, items[0].json is the usediscount response (usually `1`).
  const useResp = items[0].json;
  usedResult = useResp;
  applied = useResp === 1 || useResp === '1' || (useResp && useResp.toString && useResp.toString().trim() === '1');
  appliedDiscountRowid = $('Find discount rowid').first().json.discountRowid;
  if (!applied) {
    return [{ json: {
      ok: false,
      stage: 'usediscount',
      newInvoiceId: newId,
      validatedRef,
      action,
      parent,
      error: 'usediscount returned: ' + JSON.stringify(useResp).slice(0, 200),
      dolibarrEditUrl: `https://staging.txscorp.com/compta/facture/card.php?id=${newId}`,
    }}];
  }
}

return [{ json: {
  ok: true,
  action,
  newInvoiceId: newId,
  newInvoiceRef: validatedRef,
  validated: true,
  applied,
  appliedDiscountRowid,
  parent,
  orderNumber: input.orderNumber,
  orderRef: input.orderRef,
  amount: input.amount,
  status: 'validated' + (applied ? ' + applied' : ''),
  dolibarrEditUrl: `https://staging.txscorp.com/compta/facture/card.php?id=${newId}`,
  parentInvoiceUrl: `https://staging.txscorp.com/compta/facture/card.php?id=${parent.id}`,
  message: action === 'credit_note'
    ? `Created and validated credit note ${validatedRef} for ${input.amount.toFixed(2)}, then applied it as a discount on ${parent.ref}.`
    : `Created and validated invoice ${validatedRef} for ${input.amount.toFixed(2)} on customer ${parent.socid}.`,
}}];
